void signal_handler(int sig) {
// Atomic store with relaxed ordering
// to avoid expensive memory barriers
// on high-frequency timer interrupts.
atomic_store_relaxed(&tcb->preempt_flag, 1);
}

Context: Synchronous (Injected by Compiler)
